args.sparql:
SELECT ?bookSeriesLabel WHERE {
  ?series wdt:P31 wd:Q18232956 ;
          rdfs:label "Game of Thrones"@en.
  ?series wdt:P5286 ?bookSeries.
  ?bookSeries rdfs:label ?bookSeriesLabel.
  FILTER(LANGMATCHES(LANG(?bookSeriesLabel), "en"))
}

SELECT ?book ?bookLabel WHERE {
  wd:Q746834 wdt:P145 ?bookSeries.
  ?bookSeries wdt:P1328 ?book.
  ?book rdfs:label ?bookLabel.
  FILTER(LANGMATCHES(LANG(?bookLabel), "en"))
}

SELECT ?seriesLabel WHERE {
  wd:Q515543 wdt:P356 ?series.
  ?series rdfs:label ?seriesLabel.
  FILTER(LANGMATCHES(LANG(?seriesLabel), "en"))
}
